SELECT 
FROM schedule_slot
WHERE counselor_user_id = #{counselorUserId}
AND date BETWEEN #{startDate} AND #{endDate}
AND deleted = 0
ORDER BY date ASC, start_time ASC

SELECT 
FROM schedule_slot
WHERE counselor_user_id = #{counselorUserId}
  AND date = #{date}
  AND start_time = #{startTime}
  AND end_time = #{endTime}
  AND deleted = 0
LIMIT 1

SELECT 
FROM schedule_slot
WHERE counselor_user_id = #{counselorUserId}
  AND date = #{date}
  AND start_time <= #{startTime}
  AND end_time >= #{endTime}
  AND status = 'AVAILABLE'
  AND deleted = 0
ORDER BY start_time ASC

SELECT DISTINCT counselor_user_id
FROM schedule_slot
WHERE deleted = 0
  AND status = 'AVAILABLE'
  AND date BETWEEN #{startDate} AND #{endDate}
  AND counselor_user_id IN

      #{id}

  AND (
    date > #{today}
    OR (date = #{today} AND start_time > #{nowTime})
  )

